var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"하지만 내가 움직일 수 없는 건 사실이야.","JPN":"でも、私が直接動けないって話は本当よ。","ENG":"But it's true. I can't move right now.","TWN":"但是我確實沒辦法出去。"},"stage":{"bg":"MANSION_NIGHT","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"자매님은 모르겠지만, 외출 금지 명령을 내린 사람은 정말 무섭거든.","JPN":"シスターさんにはわからないでしょうけど、私に外出禁止命令を出した人は本当に怖い人なの。","ENG":"You don't know who she is, but the one who put me under house arrest... is terrifying.","TWN":"你有所不知，下達外出禁令的人真的很可怕。"},"stage":{"bg":"MANSION_NIGHT","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"하, 하지만…….","JPN":"で、でも……","ENG":"B-but...","TWN":"可，可是……"},"stage":{"bg":"MANSION_NIGHT","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"확실한 방법은 성황청에 도움을 요청하는 거지.","JPN":"確実な方法は、聖皇庁に助けを求めることね。","ENG":"The best option is to call for help from the Holy Curia.","TWN":"最可靠的方法是請求聖皇廳的幫助。"},"stage":{"bg":"MANSION_NIGHT","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"성황청의 견습이라며?","JPN":"あなた、聖皇庁の見習いなんでしょう？","ENG":"You're an apprentice there, aren't you?","TWN":"聽說你是聖皇廳的實習生？"},"stage":{"bg":"MANSION_NIGHT","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"어린 양이 위험에 빠졌다는데 쉽게 저버릴 리가 없지 않을까?","JPN":"子羊が危機に晒されたというのに、見捨てたりはしないんじゃない？","ENG":"They wouldn't just abandon a little lamb in danger.","TWN":"小羊陷入危險，聖皇廳應該不會見死不救吧？"},"stage":{"bg":"MANSION_NIGHT","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그건 맞는 말이에요. 하, 하지만…….","JPN":"それは間違いありません。で、でも……","ENG":"That's... true. But still...","TWN":"你說的對，但是……"},"stage":{"bg":"MANSION_NIGHT","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"지원만 기다리다간 너무 늦어버릴지도 모르지.","JPN":"助けを待っているだけじゃ、間に合わないかもしれない。","ENG":"Of course, if you just sit and wait for backup, it might be too late.","TWN":"如果只等待支援，可能會來不及。"},"stage":{"bg":"MANSION_NIGHT","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"맞아요…….","JPN":"そうなんです……","ENG":"...Yes.","TWN":"沒錯……"},"stage":{"bg":"MANSION_NIGHT","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"멍멍이는 어떻게든 살아남을 거야.","JPN":"ワンちゃんはなんとか生き延びるわ。","ENG":"Puppy will survive somehow.","TWN":"但狗狗一定會活下來的。"},"stage":{"bg":"MANSION_NIGHT","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"성황청을 부른다면 이후엔 일사천리일 테니까.","JPN":"聖皇庁を呼びさえすれば、後は順調に進むはずだから。","ENG":"Once the Holy Curia gets involved, things will move quickly.","TWN":"撐到聖皇廳的支援過來，接下來就會沒事了。"},"stage":{"bg":"MANSION_NIGHT","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"물론 돈도 못 받을 거고, 성황청에게 끌려가 이단 심판을 받게 되겠지만.","JPN":"もちろんお金はもらえないでしょうし、聖皇庁に連れていかれて異端尋問を受けることになるでしょうけどね。","ENG":"Though... she won't get paid. And then they'll drag her off for a heretic inquisition.","TWN":"當然，錢是拿不到了，還會被聖皇廳抓去接受異端審判。"},"stage":{"bg":"MANSION_NIGHT","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MANSION_NIGHT","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"이단 심판관들은 자비가 없다고 들었는데.","JPN":"異端審問官たちは容赦がないと聞いたわ。","ENG":"I hear the inquisitors aren't very merciful.","TWN":"聽說異端審判官毫無憐憫之心。"},"stage":{"bg":"MANSION_NIGHT","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"어쩌면…… 평생 지하 감옥에서 썩을 지도…….","JPN":"もしかすると……一生地下牢に閉じ込められてしまうかも……","ENG":"She might just rot in a dungeon for the rest of her life...","TWN":"或許……會在地下監獄裡關到腐爛……"},"stage":{"bg":"MANSION_NIGHT","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"흠~ 그렇게 되면 정말 큰일이겠네~","JPN":"うーん……そうなったら本当に大変でしょうね～","ENG":"Hmm... That would be quite the tragedy, wouldn't it?","TWN":"嗯～那樣的話真的會出大事的～"},"stage":{"bg":"MANSION_NIGHT","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"윽…… 맞아요.","JPN":"うっ……そうです。","ENG":"Ngh... You're right.","TWN":"呃……對的。"},"stage":{"bg":"MANSION_NIGHT","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"역시…… 불량식품은 제 손으로 구할 수밖에 없겠어요.","JPN":"やっぱり……お菓子さんは自分の手で助けるしかありません。","ENG":"Looks like I have no choice but to save Junk food myself.","TWN":"果然……還是得我親自去找啊。"},"stage":{"bg":"MANSION_NIGHT","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"무, 물론 저는 오늘 처음 본 사람이고…….","JPN":"も、もちろん、私にとっては今日会ったばかりの人ですし……","ENG":"I-I mean, I only just met her today, but...","TWN":"雖，雖然我今天第一次見到她……"},"stage":{"bg":"MANSION_NIGHT","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"절대 불량식품의 피가 맛있어서 구하려는 건 아니니까…….","JPN":"お菓子さんの血が美味しいからという理由では絶対ありませんが……","ENG":"I-I'm not saving her because her blood was delicious or anything...","TWN":"先說好，我可不是因為她的血好喝才去找的……"},"stage":{"bg":"MANSION_NIGHT","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"후훗, 속마음이 뻔히 보이는 게 꼭 멍멍이랑 닮았네.","JPN":"ふふっ、考えてることが丸見えってところがワンちゃんと似てるわね。","ENG":"Haha, the way you're trying to hide your feelings is just like Puppy.","TWN":"呵呵，心裡想什麼都寫在臉上，和狗狗真像。"},"stage":{"bg":"MANSION_NIGHT","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"……치, 칭찬이죠?","JPN":"……ほ、褒めてるんですよね？","ENG":"...That's a compliment, right?","TWN":"……是，是在稱讚我吧？"},"stage":{"bg":"MANSION_NIGHT","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"그러엄. 솔직한 건 큰 장점이거든.","JPN":"ええ。素直なのはいいことよ。","ENG":"Of course. Honesty is a virtue.","TWN":"嗯，坦誠可是一個很大的優點喔。"},"stage":{"bg":"MANSION_NIGHT","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"난 솔직하지 못하니까, 그런 점이 항상 부러웠어.","JPN":"私は素直になれないタイプだから、そういうところがいつも羨ましいと思ってたの。","ENG":"I'm not very honest myself, so I find it... admirable.","TWN":"我就不夠坦誠，所以總是很羡慕。"},"stage":{"bg":"MANSION_NIGHT","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"하긴, 돈 밝히는 거 보면 솔직해도 너무 솔직하긴 해요.","JPN":"確かに、金に目がないのを見ると、欲望に素直すぎますよね。","ENG":"Well, considering how money-obsessed she is, maybe she's a little too honest.","TWN":"也是，看她那麼愛錢，真是太坦誠了。"},"stage":{"bg":"MANSION_NIGHT","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MANSION_NIGHT","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"저는 불량식품이 감염자라는 걸 알았을 때 되게 기뻤어요.","JPN":"私、お菓子さんが感染者だとわかった時、嬉しかったんです。","ENG":"When I found out Junk food was afflicted... I was relieved.","TWN":"當我知道垃圾食物是感染者時，我真的很高興。"},"stage":{"bg":"MANSION_NIGHT","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};